    ["last"] = { -- Lời nhắc tên cuối cùng ẩn (Chữ cái đầu tiên %s: Chữ cái đầu tiên của tên họ, Chữ cái thứ hai %s: Chữ cái cuối cùng của tên họ / Chữ cái thứ ba %s: Tuổi / Chữ cái thứ tư %s: Tên đầu tiên)
        [1] = "%s---%s từ %s, một ngân hàng dày dạn kinh nghiệm tên %s, dẫn đầu với kiến thức rộng lớn và cái nhìn sâu sắc đặc biệt. Kế hoạch tài chính chiến lược của họ giúp khách hàng đạt được mục tiêu dài hạn của mình.",
