        [7] = "%s---%s ở %s, một chuyên gia đầu tư tên %s, điều hướng sự phức tạp của thị trường một cách dễ dàng. Kinh nghiệm đa dạng về danh mục đầu tư của cô ấy bảo vệ khách hàng khỏi các rủi ro không lường trước.",
        [8] = "%s---%s từ %s, tên %s, khuyến khích các chương trình giáo dục tài chính, trao quyền cho thế hệ tiếp theo. Sự cống hiến của họ đối với giáo dục đảm bảo một tương lai tài chính an toàn hơn.",
