    },

    ["residence"] = { -- Lời nhắc cư trú ẩn (Chữ cái đầu tiên %s: Tên đầu tiên / Chữ cái thứ hai %s: Tuổi / Chữ cái thứ ba %s: Chữ cái đầu tiên của nơi cư trú / Chữ cái thứ tư %s: Chữ cái cuối cùng của nơi cư trú)
        [1] = "Gặp %s, thiên tài ngân hàng. Chỉ mới %s tuổi, họ là một trong những nhà phân tích dữ liệu trẻ nhất và xuất sắc nhất ở bang %s---%s. Một tầm nhìn với sự chính trực không lay chuyển, Alex tìm cách cách mạng hóa ngành ngân hàng và để lại dấu ấn lâu dài trong tương lai tài chính của khách hàng.",
        [2] = "Giới thiệu %s, một bậc thầy ngân hàng, mới chỉ %s tuổi, và đã là một trong những nhà phân tích dữ liệu sáng giá nhất trong bang sôi động %s---%s. Với tư duy tầm nhìn và đạo đức không lay chuyển, họ mong muốn định hình lại ngành ngân hàng và tạo ra tác động tích cực lâu dài trên hành trình tài chính của khách hàng.",
        [3] = "Bước vào thế giới của %s, thiên tài ngân hàng trẻ tuổi, chỉ mới %s, đứng trong số những nhà phân tích dữ liệu tốt nhất của bang trong bang náo nhiệt %s---%s. Được dẫn dắt bởi tinh thần tầm nhìn và sự chính trực không lay chuyển, họ mong muốn cách mạng hóa bối cảnh ngân hàng, hướng dẫn khách hàng của mình đến chân trời tài chính thịnh vượng.",
        [4] = "Gặp %s, chuyên gia tài chính tiên phong mới chỉ %s tuổi, nổi bật là một trong những nhà phân tích dữ liệu xuất sắc nhất trong bang phát triển %s---%s. Với cam kết không ngừng đối với sự chính trực và cách tiếp cận tầm nhìn, họ mong muốn định nghĩa lại các thực hành ngân hàng và tạo ra tác động lâu dài đến sự an toàn tài chính của khách hàng.",
        [5] = "Khám phá %s, %s tuổi, tạo sóng ở bang đa dạng %s---%s. Với sự thông minh tầm nhìn và các nguyên tắc đạo đức không lay chuyển, họ mong muốn cách mạng hóa lĩnh vực ngân hàng, trao quyền cho khách hàng để đạt được sự thịnh vượng tài chính bền vững.",
        [6] = "Tham gia cùng %s, tài năng ngân hàng xuất sắc chỉ mới %s tuổi, đang thăng tiến để trở thành một trong những chuyên gia thuế hàng đầu của bang trong %s---%s. Được thúc đẩy bởi các mục tiêu tầm nhìn và sự chính trực không lay chuyển, họ tìm cách cách mạng hóa các thực hành ngân hàng, hướng dẫn khách hàng về một tương lai tài chính an toàn và thịnh vượng.",
        [7] = "Bước vào vương quốc của %s, trí tuệ tài chính sáng giá, %s tuổi, đang tạo dấu ấn như một trong những cố vấn ngân hàng hàng đầu của bang tại %s---%s. Được dẫn dắt bởi tinh thần tầm nhìn và đạo đức kiên định, họ tìm cách định hình lại bối cảnh ngân hàng, đảm bảo một tác động lâu dài đến thành công tài chính của khách hàng.",
        [8] = "Chào mừng đến với thế giới của %s, một thiên tài tài chính chỉ mới %s tuổi, đang nổi lên như một trong những cố vấn ngân hàng tốt nhất ở bang duyên dáng %s---%s. Với cách tiếp cận tầm nhìn và cam kết không ngừng với sự chính trực, họ mong muốn định nghĩa lại các thực hành ngân hàng, đảm bảo rằng giấc mơ tài chính của khách hàng được thực hiện.",
        [9] = "Gặp %s, nhà ngân hàng thiên tài sáng giá, chỉ mới %s tuổi, đã đứng cao trong số các chuyên gia thuế hàng đầu của bang ở %s---%s. Với tư duy tầm nhìn và đạo đức không lay chuyển, họ mong muốn cách mạng hóa ngành ngân hàng, vạch ra con đường cho sự an toàn tài chính lâu dài cho khách hàng.",
        [10] = "Ôm trọn sự xuất sắc của %s, thiên tài ngân hàng, %s tuổi, nổi bật là một trong những chuyên gia thuế sáng giá nhất ở bang sống động %s---%s. Với các mục tiêu tầm nhìn và nguyên tắc không lay chuyển, họ mong muốn định nghĩa lại các thực hành ngân hàng, hướng dẫn khách hàng về một tương lai đầy đủ tài chính.",
        [11] = "Giới thiệu %s, chuyên gia tài chính tiên phong, %s tuổi, đã nằm trong số các cố vấn ngân hàng ưu tú của bang tại %s---%s. Được thúc đẩy bởi tinh thần tầm nhìn và sự chính trực kiên định, họ mong muốn định hình lại bối cảnh ngân hàng, đảm bảo sự thịnh vượng tài chính của khách hàng không bị giới hạn.",
        [12] = "Gặp %s, một nhà lãnh đạo tài chính có tầm nhìn, %s tuổi, đang thăng tiến lên hàng ngũ các cố vấn ngân hàng hàng đầu của bang tại %s---%s. Được dẫn dắt bởi các nguyên tắc không lay chuyển, họ tìm cách cách mạng hóa ngành ngân hàng, để lại tác động sâu sắc đến tương lai tài chính của khách hàng.",
        [13] = "Bước vào thế giới của %s, chiến lược gia tài chính xuất sắc, %s tuổi, được công nhận là một trong những nhà đầu tư có tầm nhìn hàng đầu của bang sôi động %s---%s. Với các mục tiêu tầm nhìn và cam kết không ngừng với đạo đức, họ mong muốn định nghĩa lại các thực hành ngân hàng và trao quyền cho khách hàng hướng tới thành công tài chính.",
        [14] = "Khám phá %s, một nhà tư vấn tài chính trẻ và sáng giá, %s tuổi, đang tạo sóng ở bang đa dạng %s---%s. Với tư duy đổi mới và sự chính trực không lay chuyển, họ mong muốn định hình lại bối cảnh ngân hàng, mở đường cho sự thịnh vượng tài chính lâu dài của khách hàng.",
        [15] = "Tham gia cùng %s, tài năng ngân hàng xuất sắc chỉ mới %s tuổi, đang nổi lên như một trong những nhà đầu tư có tầm nhìn hàng đầu của bang tại %s---%s. Được dẫn dắt bởi một cách tiếp cận tầm nhìn và đạo đức không lay chuyển, họ tìm cách cách mạng hóa các thực hành ngân hàng, hướng dẫn khách hàng về một tương lai tài chính an toàn và phát triển.",
        [16] = "Bước vào vương quốc của %s, thiên tài tài chính sâu sắc, %s tuổi, đang để lại dấu ấn như một trong những cố vấn ngân hàng hàng đầu của bang tại %s---%s. Với tư duy tầm nhìn và nguyên tắc không lay chuyển, họ tìm cách định hình lại ngành ngân hàng, đảm bảo một tác động lâu dài đến thành công tài chính của khách hàng.",
        [17] = "Chào mừng đến với thế giới của %s, chuyên gia tài chính thiên tài, %s tuổi, đã đứng cao trong số các cố vấn ngân hàng hàng đầu của bang tại %s---%s. Với tinh thần tầm nhìn và đạo đức không lay chuyển, họ mong muốn định hình lại bối cảnh ngân hàng, mở đường cho sự tăng trưởng tài chính bền vững của khách hàng.",
        [18] = "Gặp %s, thiên tài ngân hàng đổi mới, %s tuổi, đang nổi bật là một trong những nhà đầu tư có tầm nhìn tốt nhất ở bang sôi động %s---%s. Với cách tiếp cận tầm nhìn và sự chính trực không lay chuyển, họ mong muốn định nghĩa lại các thực hành ngân hàng, đảm bảo rằng giấc mơ tài chính của khách hàng trở thành hiện thực.",
        [19] = "Ôm trọn sự xuất sắc của %s, thiên tài ngân hàng nổi tiếng, %s tuổi, nổi bật là một trong những nhà đầu tư có tầm nhìn sáng giá nhất ở bang năng động %s---%s. Với các mục tiêu tầm nhìn và nguyên tắc không lay chuyển, họ mong muốn định nghĩa lại các thực hành ngân hàng, hướng dẫn khách hàng về một tương lai đầy đủ tài chính.",
        [20] = "Giới thiệu %s, bậc thầy ngân hàng, chỉ mới %s tuổi, đã được đếm vào số những cố vấn tài chính hàng đầu của bang tại %s---%s. Với tư duy tầm nhìn và đạo đức không lay chuyển, họ mong muốn định hình lại ngành ngân hàng, đảm bảo một con đường tài chính thành công và bền vững cho khách hàng.",
    },

    ["age"] = { -- Lời nhắc tuổi ẩn (Chữ cái đầu tiên %s: Tên đầu tiên / Chữ cái thứ hai %s: Nơi cư trú / *: Tuổi)
        [1] = "%s ở %s, một nhà phân tích tài chính có đạo đức thúc đẩy các khoản đầu tư bền vững cho một thế giới xanh hơn. Với một ý thức sâu sắc về trách nhiệm, nhà phân tích có kinh nghiệm này, * tuổi, phù hợp các mục tiêu tài chính của khách hàng với quản lý môi trường.",
        [2] = "%s từ %s, phát triển mạnh trong việc giải quyết các vấn đề thuế phức tạp cho các khách hàng doanh nghiệp. Với các kỹ năng phân tích sắc bén và kinh nghiệm phong phú, chuyên gia thuế này, * tuổi, điều hướng các tình huống tài chính phức tạp một cách dễ dàng.",
        [3] = "%s ở %s, xây dựng các mối quan hệ đối tác lâu dài với các tổ chức từ thiện, thúc đẩy tác động xã hội tích cực. Với trái tim hướng thiện và kinh nghiệm sâu rộng, nhà chiến lược thiện nguyện này, * tuổi, sử dụng chuyên môn tài chính để tăng cường hiệu quả của các sáng kiến xã hội.",
        [4] = "%s từ %s, là người tiên phong đầu tư, tái định hình ngành công nghiệp thông qua các công nghệ tiên tiến. Ở tuổi * tuổi, nhà đầu tư tầm nhìn này dự đoán một kỷ nguyên mới của các dịch vụ đầu tư tập trung vào khách hàng được tăng cường bởi các tiến bộ công nghệ.",
        [5] = "%s ở %s, chuyên về mua bán và sáp nhập, tổ chức các giao dịch thành công cho các khách hàng doanh nghiệp. Với con mắt sắc bén cho cơ hội và kinh nghiệm lâu năm, chuyên gia M&A này, * tuổi, tối đa hóa giá trị cho tất cả các bên liên quan trong các giao dịch phức tạp.",
        [6] = "%s từ %s, trao quyền cho các doanh nhân đa dạng, thu hẹp khoảng cách tài chính cho các cộng đồng thiếu đại diện. Với sự cam kết đối với tài chính bao gồm và kinh nghiệm sâu rộng, nhà tư vấn phát triển kinh doanh này, * tuổi, thúc đẩy sự bình đẳng kinh tế cho tất cả các chủ doanh nghiệp đầy tham vọng.",
        [7] = "%s ở %s, giúp các gia đình đảm bảo tương lai của mình thông qua kế hoạch bất động sản thận trọng. Với cách tiếp cận chu đáo và kinh nghiệm lâu năm, nhà lập kế hoạch bất động sản này, * tuổi, cung cấp hướng dẫn tài chính cá nhân hóa để đảm bảo việc chuyển giao tài sản suôn sẻ giữa các thế hệ.",
        [8] = "%s từ %s, ở tuổi *, là một chuyên gia tư vấn tài chính có kinh nghiệm sâu rộng. Với sự hiểu biết sâu sắc về ngành công nghiệp tài chính và nhiều năm thực hành thành công, chuyên gia tư vấn này tiếp tục là một động lực thúc đẩy trong ngành.",
        [9] = "%s ở %s, là một nhà quản lý tài sản đáng tin cậy, bảo tồn và phát triển tài sản của khách hàng cho các thế hệ tương lai. Với trọng tâm vào sự thịnh vượng lâu dài và nhiều năm kinh nghiệm, nhà quản lý tài sản này, * tuổi, bảo vệ di sản tài chính của khách hàng.",
        [10] = "%s từ %s, là một kiến trúc sư giải pháp ngân hàng am hiểu công nghệ, tận dụng các đổi mới kỹ thuật số để nâng cao trải nghiệm khách hàng. Với niềm đam mê đổi mới và nhiều năm kinh nghiệm, kiến trúc sư giải pháp này tiên phong các giải pháp ngân hàng tiên tiến cho một hành trình khách hàng liền mạch.",
        [11] = "%s ở %s, thúc đẩy kiến thức tài chính trong thanh niên, truyền cảm hứng cho thế hệ nhà đầu tư tiếp theo. Với sự cống hiến cho giáo dục tài chính và nhiều năm kinh nghiệm, nhà giáo dục tài chính này, * tuổi, trao quyền cho những người trẻ tuổi để đưa ra các quyết định tài chính sáng suốt.",
        [12] = "%s từ %s, ở tuổi *, là một nhà lãnh đạo tầm nhìn trong ngành đầu tư. Với các sáng kiến đột phá và kinh nghiệm sâu rộng, nhà lãnh đạo này tiếp tục định hình tương lai của tài chính.",
        [13] = "%s ở %s, là một doanh nhân fintech sáng tạo, giới thiệu các công nghệ mới cho sự thành công tài chính của khách hàng, ở tuổi * tuổi. Với một góc nhìn mới mẻ và kinh nghiệm sâu rộng, doanh nhân này mang đến các giải pháp fintech đột phá.",
        [14] = "%s từ %s, là một cố vấn tài chính đồng cảm, cung cấp hướng dẫn cá nhân hóa cho khách hàng. Với cách tiếp cận đồng cảm và nhiều năm kinh nghiệm, * tuổi, cố vấn này đảm bảo phúc lợi tài chính của khách hàng.",
        [15] = "%s ở %s, là một bậc thầy phân tích, tận dụng các dữ liệu chi tiết để đưa ra các quyết định đầu tư hợp lý. Với tư duy định hướng dữ liệu và nhiều năm kinh nghiệm, nhà phân tích tài chính này xác định các cơ hội sinh lợi cho khách hàng.",
        [16] = "%s từ %s, là một chuyên gia quản lý rủi ro dày dạn kinh nghiệm, bảo vệ khách hàng khỏi các cạm bẫy tài chính. Với con mắt tinh tường về rủi ro và nhiều năm kinh nghiệm ở tuổi *, chuyên gia quản lý rủi ro này củng cố vị trí tài chính của khách hàng.",
        [17] = "%s ở %s, là một chiến lược gia tiếp thị năng động, định hướng các tổ chức tài chính đến thành công. Với kỹ năng tiếp thị đặc biệt và nhiều năm kinh nghiệm ở tuổi *, chiến lược gia này truyền cảm hứng cho các nhóm để đạt được kết quả đáng kể.",
        [18] = "%s từ %s, là một nhà đàm phán kiên định, đảm bảo các điều khoản có lợi cho khách hàng. Với khả năng đàm phán sắc bén và nhiều năm kinh nghiệm, * tuổi, nhà đàm phán này thúc đẩy các thỏa thuận có lợi cho khách hàng của mình.",
        [19] = "%s ở %s, là một người giải quyết vấn đề sáng tạo, tìm ra các giải pháp sáng tạo cho các thách thức tài chính. Ở tuổi *, với khả năng suy nghĩ ngoài khuôn khổ và nhiều năm kinh nghiệm, người giải quyết vấn đề này vượt qua các rào cản tài chính phức tạp.",
        [20] = "%s từ %s, là một chuyên gia ngân hàng tập trung vào khách hàng, đặt nhu cầu của khách hàng lên hàng đầu. Ở tuổi *, với sự tận tâm đối với dịch vụ xuất sắc và nhiều năm kinh nghiệm, chuyên gia này ưu tiên sự thành công tài chính của khách hàng.",
    },

}
